INSTRUCTION_DETAILS", "SETTLEMENT_PRIORITY", "PAYMENT_TEXT_MESSAGE1", "PAYMENT_TEXT_MESSAGE2", "PAYMENT_TEXT_MESSAGE3", "IBY_BANK_CHARGE_BEARER", "PAYMENT_REASON_CODE", "PAYMENT_REASON_COMMENTS", "REMIT_ADVICE_DELIVERY_METHOD", "REMITTANCE_EMAIL", "REMITTANCE_FAX", "ATTRIBUTE_CATEGORY", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4", "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10", "ATTRIBUTE11", "ATTRIBUTE12", "ATTRIBUTE13", "ATTRIBUTE14", "ATTRIBUTE15", "ATTRIBUTE16", "ATTRIBUTE17", "ATTRIBUTE18", "ATTRIBUTE19", "ATTRIBUTE20", "ATTRIBUTE_DATE1", "ATTRIBUTE_DATE2", "ATTRIBUTE_DATE3", "ATTRIBUTE_DATE4", "ATTRIBUTE_DATE5", "ATTRIBUTE_DATE6", "ATTRIBUTE_DATE7", "ATTRIBUTE_DATE8", "ATTRIBUTE_DATE9", "ATTRIBUTE_DATE10", "ATTRIBUTE_TIMESTAMP1", "ATTRIBUTE_TIMESTAMP2", "ATTRIBUTE_TIMESTAMP3", "ATTRIBUTE_TIMESTAMP4", "ATTRIBUTE_TIMESTAMP5", "ATTRIBUTE_TIMESTAMP6", "ATTRIBUTE_TIMESTAMP7", "ATTRIBUTE_TIMESTAMP8", "ATTRIBUTE_TIMESTAMP9", "ATTRIBUTE_TIMESTAMP10", "ATTRIBUTE_NUMBER1", "ATTRIBUTE_NUMBER2", "ATTRIBUTE_NUMBER3", "ATTRIBUTE_NUMBER4", "ATTRIBUTE_NUMBER5", "ATTRIBUTE_NUMBER6", "ATTRIBUTE_NUMBER7", "ATTRIBUTE_NUMBER8", "ATTRIBUTE_NUMBER9", "ATTRIBUTE_NUMBER10", "GLOBAL_ATTRIBUTE_CATEGORY", "GLOBAL_ATTRIBUTE1", "GLOBAL_ATTRIBUTE2", "GLOBAL_ATTRIBUTE3", "GLOBAL_ATTRIBUTE4", "GLOBAL_ATTRIBUTE5", "GLOBAL_ATTRIBUTE6", "GLOBAL_ATTRIBUTE7", "GLOBAL_ATTRIBUTE8", "GLOBAL_ATTRIBUTE9", "GLOBAL_ATTRIBUTE10", "GLOBAL_ATTRIBUTE11", "GLOBAL_ATTRIBUTE12", "GLOBAL_ATTRIBUTE13", "GLOBAL_ATTRIBUTE14", "GLOBAL_ATTRIBUTE15", "GLOBAL_ATTRIBUTE16", "GLOBAL_ATTRIBUTE17", "GLOBAL_ATTRIBUTE18", "GLOBAL_ATTRIBUTE19", "GLOBAL_ATTRIBUTE20", "GLOBAL_ATTRIBUTE_DATE1", "GLOBAL_ATTRIBUTE_DATE2", "GLOBAL_ATTRIBUTE_DATE3", "GLOBAL_ATTRIBUTE_DATE4", "GLOBAL_ATTRIBUTE_DATE5", "GLOBAL_ATTRIBUTE_DATE6", "GLOBAL_ATTRIBUTE_DATE7", "GLOBAL_ATTRIBUTE_DATE8", "GLOBAL_ATTRIBUTE_DATE9", "GLOBAL_ATTRIBUTE_DATE10", "GLOBAL_ATTRIBUTE_TIMESTAMP1", "GLOBAL_ATTRIBUTE_TIMESTAMP2", "GLOBAL_ATTRIBUTE_TIMESTAMP3", "GLOBAL_ATTRIBUTE_TIMESTAMP4", "GLOBAL_ATTRIBUTE_TIMESTAMP5", "GLOBAL_ATTRIBUTE_TIMESTAMP6", "GLOBAL_ATTRIBUTE_TIMESTAMP7", "GLOBAL_ATTRIBUTE_TIMESTAMP8", "GLOBAL_ATTRIBUTE_TIMESTAMP9", "GLOBAL_ATTRIBUTE_TIMESTAMP10", "GLOBAL_ATTRIBUTE_NUMBER1", "GLOBAL_ATTRIBUTE_NUMBER2", "GLOBAL_ATTRIBUTE_NUMBER3", "GLOBAL_ATTRIBUTE_NUMBER4", "GLOBAL_ATTRIBUTE_NUMBER5", "GLOBAL_ATTRIBUTE_NUMBER6", "GLOBAL_ATTRIBUTE_NUMBER7", "GLOBAL_ATTRIBUTE_NUMBER8", "GLOBAL_ATTRIBUTE_NUMBER9", "GLOBAL_ATTRIBUTE_NUMBER10", "PO_ACK_REQD_CODE", "PO_ACK_REQD_DAYS", "INVOICE_CHANNEL", "PAYEE_SERVICE_LEVEL_CODE", "EXCLUSIVE_PAYMENT_FLAG", "OVERRIDE_B2B_COMM_CODE", "SOURCE_ID", "STG_SEQUENCE_ID", "RUN_ID", "INTEGRATION_ID", "PREFIX", "SCENARIO_ID", "STAGE_DATE", "LAST_UPDATED_DATE")  AS 
  SELECT
    -- 1. Run status
    NVL(tfm.STATUS, stg.STATUS)                             AS RUN_STATUS,
    -- 2. Error text
    tfm.ERROR_TEXT                                           AS ERROR_TEXT,
    CASE
        WHEN NVL(tfm.STATUS, stg.STATUS) = 'LOADED' THEN 'CONFIRMED'
        WHEN NVL(tfm.STATUS, stg.STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NOT NULL THEN 'CONFIRMED'
        WHEN NVL(tfm.STATUS, stg.STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NULL THEN 'UNRECONCILED'
        ELSE 'IN_PROGRESS'
    END                                                      AS RECONCILIATION_STATUS,
    -- 3. Human identifiers
    stg.VENDOR_NAME                                         AS VENDOR_NAME,
    stg.VENDOR_SITE_CODE                                    AS VENDOR_SITE_CODE,
    -- 4. All remaining STG business columns
    stg.IMPORT_ACTION,
    stg.PROCUREMENT_BUSINESS_UNIT_NAME,
    stg.PARTY_SITE_NAME,
    stg.VENDOR_SITE_CODE_NEW,
    stg.INACTIVE_DATE,
    stg.RFQ_ONLY_SITE_FLAG,
    stg.PURCHASING_SITE_FLAG,
    stg.PCARD_SITE_FLAG,
    stg.PAY_SITE_FLAG,
    stg.PRIMARY_PAY_SITE_FLAG,
    stg.TAX_REPORTING_SITE_FLAG,
    stg.VENDOR_SITE_CODE_ALT,
    stg.CUSTOMER_NUM,
    stg.B2B_COMM_METHOD_CODE,
    stg.B2B_SITE_CODE,
    stg.SUPPLIER_NOTIF_METHOD,
    stg.EMAIL_ADDRESS,
    stg.FAX_COUNTRY_CODE,
    stg.FAX_AREA_CODE,
    stg.FAX,
    stg.HOLD_FLAG,
    stg.PURCHASING_HOLD_REASON,
    stg.CARRIER,
    stg.MODE_OF_TRANSPORT_CODE,
    stg.SERVICE_LEVEL_CODE,
    stg.FREIGHT_TERMS_LOOKUP_CODE,
    stg.PAY_ON_CODE,
    stg.FOB_LOOKUP_CODE,
    stg.COUNTRY_OF_ORIGIN_CODE,
    stg.BUYER_MANAGED_TRANSPORT_FLAG,
    stg.PAY_ON_USE_FLAG,
    stg.AGING_ONSET_POINT,
    stg.AGING_PERIOD_DAYS,
    stg.CONSUMPTION_ADVICE_FREQUENCY,
    stg.CONSUMPTION_ADVICE_SUMMARY,
    stg.DEFAULT_PAY_SITE_CODE,
    stg.PAY_ON_RECEIPT_SUMMARY_CODE,
    stg.GAPLESS_INV_NUM_FLAG,
    stg.SELLING_COMPANY_IDENTIFIER,
    stg.CREATE_DEBIT_MEMO_FLAG,
    stg.ENFORCE_SHIP_TO_LOCATION_CODE,
    stg.RECEIVING_ROUTING_ID,
    stg.QTY_RCV_TOLERANCE,
    stg.QTY_RCV_EXCEPTION_CODE,
    stg.DAYS_EARLY_RECEIPT_ALLOWED,
    stg.DAYS_LATE_RECEIPT_ALLOWED,
    stg.ALLOW_SUBSTITUTE_RECEIPTS_FLAG,
    stg.ALLOW_UNORDERED_RECEIPTS_FLAG,
    stg.RECEIPT_DAYS_EXCEPTION_CODE,
    stg.INVOICE_CURRENCY_CODE,
    stg.INVOICE_AMOUNT_LIMIT,
    stg.MATCH_OPTION,
    stg.MATCH_APPROVAL_LEVEL,
    stg.PAYMENT_CURRENCY_CODE,
    stg.PAYMENT_PRIORITY,
    stg.PAY_GROUP_LOOKUP_CODE,
    stg.TOLERANCE_NAME,
    stg.SERVICES_TOLERANCE,
    stg.HOLD_ALL_PAYMENTS_FLAG,
    stg.HOLD_UNMATCHED_INVOICES_FLAG,
    stg.HOLD_FUTURE_PAYMENTS_FLAG,
    stg.HOLD_BY,
    stg.PAYMENT_HOLD_DATE,
    stg.HOLD_REASON,
    stg.TERMS_NAME,
    stg.TERMS_DATE_BASIS,
    stg.PAY_DATE_BASIS_LOOKUP_CODE,
    stg.BANK_CHARGE_DEDUCTION_TYPE,
    stg.ALWAYS_TAKE_DISC_FLAG,
    stg.EXCLUDE_FREIGHT_FROM_DISCOUNT,
    stg.EXCLUDE_TAX_FROM_DISCOUNT,
    stg.AUTO_CALCULATE_INTEREST_FLAG,
    stg.VAT_CODE,
    stg.VAT_REGISTRATION_NUM,
    stg.PAYMENT_METHOD_LOOKUP_CODE,
    stg.DELIVERY_CHANNEL_CODE,
    stg.BANK_INSTRUCTION1_CODE,
    stg.BANK_INSTRUCTION2_CODE,
    stg.BANK_INSTRUCTION_DETAILS,
    stg.SETTLEMENT_PRIORITY,
    stg.PAYMENT_TEXT_MESSAGE1,
    stg.PAYMENT_TEXT_MESSAGE2,
    stg.PAYMENT_TEXT_MESSAGE3,
    stg.IBY_BANK_CHARGE_BEARER,
    stg.PAYMENT_REASON_CODE,
    stg.PAYMENT_REASON_COMMENTS,
    stg.REMIT_ADVICE_DELIVERY_METHOD,
    stg.REMITTANCE_EMAIL,
    stg.REMITTANCE_FAX,
    stg.ATTRIBUTE_CATEGORY,
    stg.ATTRIBUTE1,
    stg.ATTRIBUTE2,
